6821 /// then try to reduce patterns based on that limit.
6822 Instruction *InstCombinerImpl::foldICmpUsingBoolRange(ICmpInst &I) {
6823   Value *X, *Y;
6824   ICmpInst::Predicate Pred;
6825 
6826   // X must be 0 and bool must be true for "ULT":
6827   // X <u (zext i1 Y) --> (X == 0) & Y
6828   if (match(&I, m_c_ICmp(Pred, m_Value(X), m_OneUse(m_ZExt(m_Value(Y))))) &&
6829       Y->getType()->isIntOrIntVectorTy(1) && Pred == ICmpInst::ICMP_ULT)
6830     return BinaryOperator::CreateAnd(Builder.CreateIsNull(X), Y);
6831 
6832   // X must be 0 or bool must be true for "ULE":
6833   // X <=u (sext i1 Y) --> (X == 0) | Y
6834   if (match(&I, m_c_ICmp(Pred, m_Value(X), m_OneUse(m_SExt(m_Value(Y))))) &&
6835       Y->getType()->isIntOrIntVectorTy(1) && Pred == ICmpInst::ICMP_ULE)
6836     return BinaryOperator::CreateOr(Builder.CreateIsNull(X), Y);
6837 
6838   // icmp eq/ne X, (zext/sext (icmp eq/ne X, C))
6839   ICmpInst::Predicate Pred1, Pred2;
6840   const APInt *C;
6841   Instruction *ExtI;
6842   if (match(&I, m_c_ICmp(Pred1, m_Value(X),
6843                          m_CombineAnd(m_Instruction(ExtI),
6844                                       m_ZExtOrSExt(m_ICmp(Pred2, m_Deferred(X),
6845                                                           m_APInt(C)))))) &&
6846       ICmpInst::isEquality(Pred1) && ICmpInst::isEquality(Pred2)) {
6847     bool IsSExt = ExtI->getOpcode() == Instruction::SExt;
6848     bool HasOneUse = ExtI->hasOneUse() && ExtI->getOperand(0)->hasOneUse();
6849     auto CreateRangeCheck = [&] {
6850       Value *CmpV1 =
6851           Builder.CreateICmp(Pred1, X, Constant::getNullValue(X->getType()));
6852       Value *CmpV2 = Builder.CreateICmp(
6853           Pred1, X, ConstantInt::getSigned(X->getType(), IsSExt ? -1 : 1));
6854       return BinaryOperator::Create(
6855           Pred1 == ICmpInst::ICMP_EQ ? Instruction::Or : Instruction::And,
6856           CmpV1, CmpV2);
6857     };
6858     if (C->isZero()) {
6859       if (Pred2 == ICmpInst::ICMP_EQ) {
6860         // icmp eq X, (zext/sext (icmp eq X, 0)) --> false
6861         // icmp ne X, (zext/sext (icmp eq X, 0)) --> true
6862         return replaceInstUsesWith(
6863             I, ConstantInt::getBool(I.getType(), Pred1 == ICmpInst::ICMP_NE));
6864       } else if (!IsSExt || HasOneUse) {
6865         // icmp eq X, (zext (icmp ne X, 0)) --> X == 0 || X == 1
6866         // icmp ne X, (zext (icmp ne X, 0)) --> X != 0 && X != 1
6867         // icmp eq X, (sext (icmp ne X, 0)) --> X == 0 || X == -1
6868         // icmp ne X, (sext (icmp ne X, 0)) --> X != 0 && X == -1
6869         return CreateRangeCheck();
6870       }
6871     } else if (IsSExt ? C->isAllOnes() : C->isOne()) {
6872       if (Pred2 == ICmpInst::ICMP_NE) {
6873         // icmp eq X, (zext (icmp ne X, 1)) --> false
6874         // icmp ne X, (zext (icmp ne X, 1)) --> true
6875         // icmp eq X, (sext (icmp ne X, -1)) --> false
6876         // icmp ne X, (sext (icmp ne X, -1)) --> true
6877         return replaceInstUsesWith(
6878             I, ConstantInt::getBool(I.getType(), Pred1 == ICmpInst::ICMP_NE));
6879       } else if (!IsSExt || HasOneUse) {
6880         // icmp eq X, (zext (icmp eq X, 1)) --> X == 0 || X == 1
6881         // icmp ne X, (zext (icmp eq X, 1)) --> X != 0 && X != 1
6882         // icmp eq X, (sext (icmp eq X, -1)) --> X == 0 || X == -1
6883         // icmp ne X, (sext (icmp eq X, -1)) --> X != 0 && X == -1
6884         return CreateRangeCheck();
6885       }
6886     } else {
6887       // when C != 0 && C != 1:
6888       //   icmp eq X, (zext (icmp eq X, C)) --> icmp eq X, 0
6889       //   icmp eq X, (zext (icmp ne X, C)) --> icmp eq X, 1
6890       //   icmp ne X, (zext (icmp eq X, C)) --> icmp ne X, 0
6891       //   icmp ne X, (zext (icmp ne X, C)) --> icmp ne X, 1
6892       // when C != 0 && C != -1:
6893       //   icmp eq X, (sext (icmp eq X, C)) --> icmp eq X, 0
6894       //   icmp eq X, (sext (icmp ne X, C)) --> icmp eq X, -1
6895       //   icmp ne X, (sext (icmp eq X, C)) --> icmp ne X, 0
6896       //   icmp ne X, (sext (icmp ne X, C)) --> icmp ne X, -1
6897       return ICmpInst::Create(
6898           Instruction::ICmp, Pred1, X,
6899           ConstantInt::getSigned(X->getType(), Pred2 == ICmpInst::ICMP_NE
6900                                                    ? (IsSExt ? -1 : 1)
6901                                                    : 0));
6902     }
6903   }
6904 
6905   return nullptr;
6906 }
