6908 std::optional<std::pair<CmpPredicate, Constant *>>
6909 InstCombiner::getFlippedStrictnessPredicateAndConstant(CmpPredicate Pred,
6910                                                        Constant *C) {
6911   assert(ICmpInst::isRelational(Pred) && ICmpInst::isIntPredicate(Pred) &&
6912          "Only for relational integer predicates.");
6913 
6914   Type *Type = C->getType();
6915   bool IsSigned = ICmpInst::isSigned(Pred);
6916 
6917   CmpInst::Predicate UnsignedPred = ICmpInst::getUnsignedPredicate(Pred);
6918   bool WillIncrement =
6919       UnsignedPred == ICmpInst::ICMP_ULE || UnsignedPred == ICmpInst::ICMP_UGT;
6920 
6921   // Check if the constant operand can be safely incremented/decremented
6922   // without overflowing/underflowing.
6923   auto ConstantIsOk = [WillIncrement, IsSigned](ConstantInt *C) {
6924     return WillIncrement ? !C->isMaxValue(IsSigned) : !C->isMinValue(IsSigned);
6925   };
6926 
6927   Constant *SafeReplacementConstant = nullptr;
6928   if (auto *CI = dyn_cast<ConstantInt>(C)) {
6929     // Bail out if the constant can't be safely incremented/decremented.
6930     if (!ConstantIsOk(CI))
6931       return std::nullopt;
6932   } else if (auto *FVTy = dyn_cast<FixedVectorType>(Type)) {
6933     unsigned NumElts = FVTy->getNumElements();
6934     for (unsigned i = 0; i != NumElts; ++i) {
6935       Constant *Elt = C->getAggregateElement(i);
6936       if (!Elt)
6937         return std::nullopt;
6938 
6939       if (isa<UndefValue>(Elt))
6940         continue;
6941 
6942       // Bail out if we can't determine if this constant is min/max or if we
6943       // know that this constant is min/max.
6944       auto *CI = dyn_cast<ConstantInt>(Elt);
6945       if (!CI || !ConstantIsOk(CI))
6946         return std::nullopt;
6947 
6948       if (!SafeReplacementConstant)
6949         SafeReplacementConstant = CI;
6950     }
6951   } else if (isa<VectorType>(C->getType())) {
6952     // Handle scalable splat
6953     Value *SplatC = C->getSplatValue();
6954     auto *CI = dyn_cast_or_null<ConstantInt>(SplatC);
6955     // Bail out if the constant can't be safely incremented/decremented.
6956     if (!CI || !ConstantIsOk(CI))
6957       return std::nullopt;
6958   } else {
6959     // ConstantExpr?
6960     return std::nullopt;
6961   }
6962 
6963   // It may not be safe to change a compare predicate in the presence of
6964   // undefined elements, so replace those elements with the first safe constant
6965   // that we found.
6966   // TODO: in case of poison, it is safe; let's replace undefs only.
6967   if (C->containsUndefOrPoisonElement()) {
6968     assert(SafeReplacementConstant && "Replacement constant not set");
6969     C = Constant::replaceUndefsWith(C, SafeReplacementConstant);
6970   }
6971 
6972   CmpInst::Predicate NewPred = CmpInst::getFlippedStrictnessPredicate(Pred);
6973 
6974   // Increment or decrement the constant.
6975   Constant *OneOrNegOne = ConstantInt::get(Type, WillIncrement ? 1 : -1, true);
6976   Constant *NewC = ConstantExpr::getAdd(C, OneOrNegOne);
6977 
6978   return std::make_pair(NewPred, NewC);
6979 }
